#include<bits/stdc++.h>
using namespace std;
int k;
long long n,e,d;
int main()
{
    cin>>k;
    while(k--)
    {
        cin>>n>>e>>d;
        long long m=n-e*d+2;
        long long l=1,r=m/2,mid;
        while(l<=r)
        {
            mid=(l+r)/2;
            if(mid*(m-mid)<n) l=mid+1;
            else if(mid*(m-mid)>n) r=mid-1;
            else break;
        }
        if(l>r) cout<<"NO\n";
        else cout<<mid<<' '<<m-mid<<'\n';
    }
    return 0;
}
